import { get, post } from "../ultils/request";

export const login = async (username, password) => {
  const payload = {
    username,
    password,
  };
  const result = await post("api/auth/login", payload); // Gửi payload trong body
  return result;
};
export const register = async (options) => {
  const result = await post("api/auth/login", options);
  return result;
};

export const checkExit = async (key, value) => {
  const result = await get(`usersprofile?${key}=${value}`);
  return result;
};
